<template>
  <view v-if="preview" class="page-shell"><view class="rule-card" :class="{ blocked: !preview.cancellable }"><view class="rule-icon"><u-icon :name="preview.cancellable ? 'rmb-circle-fill' : 'info-circle-fill'" size="34" color="#FFFFFF" /></view><view><text class="rule-title">{{ preview.ruleTitle }}</text><text class="rule-desc">{{ preview.ruleDescription }}</text></view></view><view class="amount-card"><view class="amount-row"><text>订单金额</text><text>¥{{ preview.totalAmount }}</text></view><view class="amount-row"><text>扣除金额</text><text class="deduction">- ¥{{ preview.deductionAmount }}</text></view><view class="amount-row total"><text>预计退款</text><text>¥{{ preview.refundAmount }}</text></view></view><view v-if="preview.cancellable" class="form-card"><text class="section-title">取消原因</text><view class="reason-grid"><text v-for="option in reasons" :key="option" :class="{ active: reason === option }" @click="reason = option">{{ option }}</text></view><textarea v-model="remark" maxlength="200" class="remark-input" placeholder="可以补充说明具体原因" /></view><view class="notice"><u-icon name="info-circle" size="18" color="#8E9DAE" /><text>退款金额和规则以服务阶段为准。Mock 约 8 秒后完成退款，真实环境以后端支付渠道结果为准。</text></view><button v-if="preview.cancellable" class="submit-button" :disabled="submitting" @click="submit">{{ submitting ? '提交中...' : '确认取消订单' }}</button><button v-else class="back-button" @click="uni.navigateBack()">返回订单详情</button></view>
</template>
<script setup>
import { computed, ref } from 'vue'
import { onLoad } from '@dcloudio/uni-app'
import { useAftersalesStore } from '@/store/aftersales.js'
const store = useAftersalesStore(); const orderId = ref(null); const reason = ref('计划有变'); const remark = ref(''); const submitting = ref(false); const preview = computed(() => store.cancelPreview); const reasons = ['计划有变', '服务时间不合适', '地址填写错误', '等待时间过长', '其他原因']; onLoad(async (options) => { orderId.value = Number(options.id); await store.previewCancellation(orderId.value) }); async function submit() { submitting.value = true; try { await store.cancelOrder(orderId.value, `${reason.value}${remark.value.trim() ? `：${remark.value.trim()}` : ''}`); uni.showToast({ title: preview.value.refundAmount > 0 ? '取消成功，退款处理中' : '订单已取消', icon: 'success' }); setTimeout(() => uni.redirectTo({ url: `/pages/order/order-detail?id=${orderId.value}` }), 700) } finally { submitting.value = false } }
</script>
<style lang="scss" scoped>
