radius: 20rpx; color: $text-color-hint; background: rgba(240,243,247,.78); font-size: $font-size-xs; line-height: 1.55; }.submit-button,.back-button { width: 100%; height: 82rpx; margin-top: 22rpx; border: 0; border-radius: $radius-round; line-height: 82rpx; }.submit-button { color: #fff; background: linear-gradient(135deg,#e7833b,#f4a259); }.back-button { color: $primary-color; background: $primary-bg; }.submit-button::after,.back-button::after { border: 0; }
</style>
